// // Synchronized D flip-flop with active-high reset. On the falling edge of the clock, the flip-flop captures the value of input 'd' and outputs it on 'q'. If the reset signal is asserted (high), the output 'q' is set to zero regardless of the clock input.
module top_module(
  input clk, rst, d,
  output reg q
);always @(posedge clk or negedge rst) begin
    if (!rst) begin
      q <= 0;
    end else begin
      q <= d;
    end
  end

endmodule
